    public static long solve(long[] nums) {
        List<Long> indicesOfOne = new ArrayList<>();
        List<Long> indicesOfTwo = new ArrayList<>();
        int N = nums.length;

        // 1. Collect indices of 1s and 2s
        for (int k = 0; k < N; k++) {
            if (nums[k] == 1L) {
                indicesOfOne.add((long)k);
            } else if (nums[k] == 2L) {
                indicesOfTwo.add((long)k);
            }
        }

        // 2. Handle the case where no valid pair can exist
        if (indicesOfOne.isEmpty() || indicesOfTwo.isEmpty()) {
            return -1L;
        }

        // 3. Find the minimum absolute difference
        long minDiff = Long.MAX_VALUE;

        for (long i : indicesOfOne) {
            for (long j : indicesOfTwo) {
                long diff = Math.abs(i - j);
                if (diff < minDiff) {
                    minDiff = diff;
                }
            }
        }

        return minDiff;
    }
}

